import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

// ===== 主题色 / 暗黑模式工具 =====

const THEME_STORAGE_KEY = 'h5-theme';

export type ThemeMode = 'light' | 'dark';

/** 读取本地存储的主题模式，默认 light */
export function getStoredTheme(): ThemeMode {
  const v = localStorage.getItem(THEME_STORAGE_KEY);
  return v === 'dark' ? 'dark' : 'light';
}

/** 持久化并应用主题模式到 <html> 上 */
export function applyThemeMode(mode: ThemeMode) {
  localStorage.setItem(THEME_STORAGE_KEY, mode);
  const root = document.documentElement;
  if (mode === 'dark') root.classList.add('dark');
  else root.classList.remove('dark');
}

/** 切换主题模式并返回新模式 */
export function toggleThemeMode(): ThemeMode {
  const next: ThemeMode = getStoredTheme() === 'dark' ? 'light' : 'dark';
  applyThemeMode(next);
  return next;
}

/** 把 hex 颜色解析为 [r, g, b]，失败时返回 null */
function hexToRgb(hex: string): [number, number, number] | null {
  let h = hex.trim().replace(/^#/, '');
  if (h.length === 3) {
    h = h.split('').map((c) => c + c).join('');
  }
  if (h.length !== 6 || !/^[0-9a-fA-F]{6}$/.test(h)) return null;
  const r = parseInt(h.slice(0, 2), 16);
  const g = parseInt(h.slice(2, 4), 16);
  const b = parseInt(h.slice(4, 6), 16);
  return [r, g, b];
}

function rgbToHex(r: number, g: number, b: number): string {
  const toHex = (n: number) => Math.max(0, Math.min(255, Math.round(n))).toString(16).padStart(2, '0');
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`;
}

/** 把主色调亮（mix 白色） */
function lighten(hex: string, amount: number): string {
  const rgb = hexToRgb(hex);
  if (!rgb) return hex;
  const [r, g, b] = rgb;
  return rgbToHex(r + (255 - r) * amount, g + (255 - g) * amount, b + (255 - b) * amount);
}

/** 把主色调暗（mix 黑色） */
function darken(hex: string, amount: number): string {
  const rgb = hexToRgb(hex);
  if (!rgb) return hex;
  const [r, g, b] = rgb;
  return rgbToHex(r * (1 - amount), g * (1 - amount), b * (1 - amount));
}

/**
 * 把主题色应用到 :root 的 CSS 变量上。
 * 会同时设置 --theme-color、--theme-color-rgb、--theme-color-dark(-rgb)、--theme-color-light(-rgb)。
 * light 变体会根据当前是否暗黑模式生成不同明度（暗黑下为深色背景，亮色下为浅色背景）。
 */
export function applyThemeColor(hex: string) {
  const fallback = '#00b578';
  const color = hexToRgb(hex) ? hex : fallback;
  const rgb = hexToRgb(color)!;
  const dark = darken(color, 0.18);
  const isDark = typeof document !== 'undefined' && document.documentElement.classList.contains('dark');
  // 亮色模式：light 为主题色与白色混合（浅色背景）
  // 暗黑模式：light 为主题色与深色混合（深色背景，避免浅色突兀）
  const light = isDark ? darken(color, 0.72) : lighten(color, 0.88);
  const darkRgb = hexToRgb(dark)!;
  const lightRgb = hexToRgb(light)!;
  const root = document.documentElement;
  root.style.setProperty('--theme-color', color);
  root.style.setProperty('--theme-color-rgb', `${rgb[0]} ${rgb[1]} ${rgb[2]}`);
  root.style.setProperty('--theme-color-dark', dark);
  root.style.setProperty('--theme-color-dark-rgb', `${darkRgb[0]} ${darkRgb[1]} ${darkRgb[2]}`);
  root.style.setProperty('--theme-color-light', light);
  root.style.setProperty('--theme-color-light-rgb', `${lightRgb[0]} ${lightRgb[1]} ${lightRgb[2]}`);
}
