import { createApp } from 'vue';
import { createPinia, setActivePinia } from 'pinia';
import piniaPluginPersistedstate from 'pinia-plugin-persistedstate';
import { MotionPlugin } from '@vueuse/motion';
import App from './App.vue';
import router from './router';
import './index.css';
// 和风天气官方图标字体（本地打包，避免依赖外部 CDN）
import 'qweather-icons/font/qweather-icons.css';
import { useAdminStore } from '@/store/useAdminStore';
import { applyThemeColor, applyThemeMode, getStoredTheme } from '@/lib/utils';

// 在挂载前根据 localStorage 应用初始主题模式，避免闪烁
applyThemeMode(getStoredTheme());

const app = createApp(App);
const pinia = createPinia();
pinia.use(piniaPluginPersistedstate);

app.use(pinia);
app.use(router);
app.use(MotionPlugin);

// 主动设置 activePinia，以便在 mount 之前就能使用 store（读取持久化的 themeColor）
setActivePinia(pinia);

// 用 store 中持久化的 themeColor 先把 CSS 变量设上（如果有），覆盖 index.css 的默认值
const adminStore = useAdminStore();
if (adminStore.systemConfig?.themeColor) {
  applyThemeColor(adminStore.systemConfig.themeColor);
}

app.mount('#app');
