<script setup lang="ts">
import { ref, watch, onMounted } from 'vue';
import { X } from 'lucide-vue-next';
import { useAdminStore } from '@/store/useAdminStore';

interface PopupItem {
  title: string;
  content: string;
}

const adminStore = useAdminStore();
const visible = ref(false);
const current = ref<PopupItem | null>(null);
const queue = ref<PopupItem[]>([]);

function checkAnnouncements() {
  const now = new Date();
  const active = adminStore.announcements
    .filter((a) => {
      if (!a.forcePopup) return false;
      if (a.expireAt) {
        const expire = new Date(a.expireAt);
        if (now > expire) return false;
      }
      return true;
    })
    .map((a) => ({ title: a.title, content: a.content }));

  if (active.length > 0) {
    const seen = JSON.parse(localStorage.getItem('seen_announcements') || '[]');
    const unseen = active.filter((a) => !seen.includes(a.title));
    if (unseen.length > 0) {
      queue.value = unseen;
      current.value = unseen[0];
      visible.value = true;
    }
  }
}

onMounted(checkAnnouncements);
watch(() => adminStore.announcements, checkAnnouncements);

function handleClose() {
  if (current.value) {
    const seen = JSON.parse(localStorage.getItem('seen_announcements') || '[]');
    if (!seen.includes(current.value.title)) {
      seen.push(current.value.title);
      localStorage.setItem('seen_announcements', JSON.stringify(seen));
    }
  }
  const nextIdx = queue.value.findIndex((a) => a.title === current.value?.title) + 1;
  if (nextIdx < queue.value.length) {
    current.value = queue.value[nextIdx];
  } else {
    visible.value = false;
    current.value = null;
  }
}
</script>

<template>
  <div v-if="visible && current" class="fixed inset-0 z-[999] flex items-center justify-center bg-black/40 px-8">
    <div class="w-full max-w-[320px] rounded-2xl bg-card p-5 shadow-xl">
      <div class="mb-3 flex items-center justify-between">
        <span class="rounded bg-[#ff9500]/10 px-2 py-0.5 text-[11px] font-medium text-[#ff9500]">
          📢 公告通知
        </span>
        <button
          type="button"
          class="flex h-7 w-7 items-center justify-center rounded-full bg-base active:scale-95"
          @click="handleClose"
        >
          <X :size="14" class="text-muted" />
        </button>
      </div>
      <h3 class="mb-2 text-[16px] font-bold text-ink">
        {{ current.title }}
      </h3>
      <p class="whitespace-pre-wrap text-[13px] leading-relaxed text-muted">
        {{ current.content }}
      </p>
      <button
        type="button"
        class="mt-4 w-full rounded-lg bg-primary py-2.5 text-[14px] font-medium text-white transition-transform active:scale-[0.98]"
        @click="handleClose"
      >
        我知道了
      </button>
    </div>
  </div>
</template>
