<script setup lang="ts">
import { computed } from 'vue';
import { useRouter, useRoute } from 'vue-router';
import { ClipboardList, Store, History } from 'lucide-vue-next';

const TABS = [
  { key: '/', label: '点名', icon: ClipboardList },
  { key: '/merchants', label: '商户', icon: Store },
  { key: '/records', label: '记录', icon: History },
];

const router = useRouter();
const route = useRoute();
const current = computed(() => route.path);

function isActive(key: string) {
  return key === '/' ? current.value === '/' : current.value.startsWith(key);
}
</script>

<template>
  <!-- iOS 毛玻璃胶囊导航：悬浮于内容底部，宽度对齐卡片 -->
  <div class="pointer-events-none absolute inset-x-0 bottom-0 z-20 flex justify-center px-gutter pb-4">
    <div
      class="pointer-events-auto flex w-full items-center gap-1 rounded-full border border-black/5 bg-white/40 p-1.5 shadow-[0_8px_30px_-6px_rgba(0,0,0,0.18)] backdrop-blur-md dark:border-white/10 dark:bg-white/10"
    >
      <button
        v-for="tab in TABS"
        :key="tab.key"
        type="button"
        class="flex flex-1 items-center justify-center gap-1.5 rounded-full px-4 py-2 transition-all active:scale-95"
        :class="isActive(tab.key)
          ? 'bg-primary text-white shadow-sm'
          : 'text-ink'"
        @click="router.push(tab.key)"
      >
        <component
          :is="tab.icon"
          :size="18"
          :stroke-width="isActive(tab.key) ? 2.5 : 2"
        />
        <span
          class="text-[13px]"
          :class="isActive(tab.key) ? 'font-semibold' : 'font-medium'"
        >
          {{ tab.label }}
        </span>
      </button>
    </div>
  </div>
</template>
