import { defineStore } from 'pinia';
import type { Merchant } from '@/types';
import { fetchMerchants, updateMerchant as apiUpdateMerchant } from '@/api/client';
import { todayStats } from '@/data/mockData';

// 历史栈条目：完整快照 + 反向 patch，保证撤销数据隔离
export interface HistoryEntry {
  merchantId: string;
  originalMerchant: Merchant; // 操作前快照
  prevIndex: number; // 操作前 currentIndex
  action: 'signedIn' | 'absent';
}

interface RollCallState {
  merchants: Merchant[];
  activeFloor: string;
  currentIndex: number;
  stats: typeof todayStats;
  activeTab: 'rollcall' | 'merchant' | 'record';
  history: HistoryEntry[]; // 操作历史栈（不持久化）
}

export const useRollCallStore = defineStore('rollcall', {
  state: (): RollCallState => ({
    merchants: [],
    activeFloor: '全部',
    currentIndex: 0,
    stats: todayStats,
    activeTab: 'rollcall',
    history: [],
  }),

  getters: {
    filteredList(state): Merchant[] {
      return filteredList(state.merchants, state.activeFloor);
    },
    // 已处理商户数（到岗 + 缺勤）
    processedCount(state): number {
      const list = filteredList(state.merchants, state.activeFloor);
      return list.filter((m) => m.signedIn || m.absent).length;
    },
    totalCount(): number {
      return this.filteredList.length;
    },
    // 全部处理完毕
    isAllDone(): boolean {
      return this.totalCount > 0 && this.processedCount >= this.totalCount;
    },
    canUndo(state): boolean {
      return state.history.length > 0;
    },
  },

  actions: {
    setActiveFloor(floor: string) {
      this.activeFloor = floor;
      this.currentIndex = 0;
      // 切换楼层清空历史栈，避免 prevIndex 失效导致串位
      this.history = [];
    },
    setCurrentIndex(i: number) {
      this.currentIndex = i;
    },
    nextMerchant() {
      const list = filteredList(this.merchants, this.activeFloor);
      if (list.length === 0) return;
      this.currentIndex = (this.currentIndex + 1) % list.length;
    },
    prevMerchant() {
      const list = filteredList(this.merchants, this.activeFloor);
      if (list.length === 0) return;
      this.currentIndex = (this.currentIndex - 1 + list.length) % list.length;
    },
    setActiveTab(tab: RollCallState['activeTab']) {
      this.activeTab = tab;
    },
    updateMerchant(id: string, patch: Partial<Merchant>) {
      this.merchants = this.merchants.map((m) => (m.id === id ? { ...m, ...patch } : m));
    },
    async loadFromApi() {
      try {
        this.merchants = await fetchMerchants();
      } catch {
        console.warn('[rollcall] loadFromApi failed');
      }
    },
    // ===== 打卡操作：先提交 API，成功后更新本地 + 入历史栈（无乐观更新，失败无回滚跳变）=====
    async checkin(id: string, action: 'signedIn' | 'absent') {
      const list = filteredList(this.merchants, this.activeFloor);
      const m = list.find((x) => x.id === id);
      if (!m) throw new Error('商户不存在');

      // 操作前快照（用于撤销恢复）
      const originalMerchant: Merchant = { ...m };
      const prevIndex = this.currentIndex;
      const patch: Partial<Merchant> =
        action === 'signedIn'
          ? { signedIn: true, signedAt: new Date().toTimeString().slice(0, 5), absent: false }
          : { absent: true, signedIn: false, signedAt: undefined };

      // 先提交后端，失败直接抛出，本地不动
      await apiUpdateMerchant(id, patch);
      // 成功 → 更新本地 + 入历史栈
      this.updateMerchant(id, patch);
      this.history.push({ merchantId: id, originalMerchant, prevIndex, action });
    },
    // ===== 撤销回退：取出最后一条，恢复其原始状态，回到该商户 =====
    async undoLast(): Promise<{ ok: boolean; reason?: string }> {
      if (this.history.length === 0) {
        return { ok: false, reason: 'no-history' };
      }
      const entry = this.history.pop()!;
      // 恢复商户到操作前快照
      this.updateMerchant(entry.merchantId, entry.originalMerchant);
      // 回到该商户位置（基于 filteredList 重算 index，防止删除/筛选变化）
      const list = filteredList(this.merchants, this.activeFloor);
      const idx = list.findIndex((x) => x.id === entry.merchantId);
      this.currentIndex = idx >= 0 ? idx : Math.min(entry.prevIndex, Math.max(0, list.length - 1));

      // 调 API 重置后端状态
      try {
        await apiUpdateMerchant(entry.merchantId, {
          signedIn: false,
          signedAt: undefined,
          absent: false,
        });
      } catch (e) {
        // API 失败不影响本地回退体验，仅告警
        console.warn('[rollcall] undoLast API failed:', e);
      }
      return { ok: true };
    },
    clearHistory() {
      this.history = [];
    },
  },

  persist: {
    key: 'rollcall-store-v2',
    storage: localStorage,
    paths: ['merchants'],
  },
});

export function filteredList(merchants: Merchant[], floor: string): Merchant[] {
  if (floor === '全部') return merchants;
  return merchants.filter((m) => m.floor === floor);
}
