<script setup lang="ts">
import { computed, watch } from 'vue';
import { useRoute } from 'vue-router';
import BottomNav from '@/components/home/BottomNav.vue';
import AnnouncementPopup from '@/components/home/AnnouncementPopup.vue';
import { useAdminStore } from '@/store/useAdminStore';
import { useRollCallStore } from '@/store/useRollCallStore';
import { applyThemeColor } from '@/lib/utils';

const route = useRoute();
const isDetail = computed(() => route.path.startsWith('/merchant/'));
const showNav = computed(() => !isDetail.value);

const adminStore = useAdminStore();
const rollcallStore = useRollCallStore();

// 启动时从 API 拉一次最新数据（systemConfig / merchants），避免 localStorage 旧缓存
adminStore.loadFromApi().catch(() => undefined);
rollcallStore.loadFromApi().catch(() => undefined);

// 主页背景图（仅主页显示；暗色模式通过 CSS .dark 选择器隐藏，保持默认背景）
const homeBgUrl = computed(() => adminStore.systemConfig?.homeBgUrl || '');
const showHomeBg = computed(() => showNav.value && homeBgUrl.value);

// 监听 themeColor 变化，动态更新 CSS 变量
watch(
  () => adminStore.systemConfig?.themeColor,
  (color) => {
    if (color) applyThemeColor(color);
  },
  { immediate: true }
);
</script>

<template>
  <div class="relative mx-auto flex h-[100dvh] w-full max-w-[430px] flex-col overflow-hidden bg-base shadow-2xl">
    <!-- 主页背景图（暗色模式隐藏，保持默认背景） -->
    <div
      v-if="showHomeBg"
      class="pointer-events-none absolute inset-0 z-0 bg-cover bg-center bg-no-repeat dark:hidden"
      :style="{ backgroundImage: `url(${homeBgUrl})` }"
    />
    <!-- 背景遮罩，让卡片毛玻璃更清晰（暗色模式隐藏） -->
    <div
      v-if="showHomeBg"
      class="pointer-events-none absolute inset-0 z-0 bg-white/10 dark:hidden"
    />
    <div class="relative z-10" :class="isDetail ? 'flex-1 overflow-y-auto' : 'flex-1 overflow-hidden'">
      <router-view v-slot="{ Component }">
        <transition name="page" mode="out-in">
          <component :is="Component" />
        </transition>
      </router-view>
    </div>
    <BottomNav v-if="showNav" />
    <AnnouncementPopup />
  </div>
</template>
