import { defineStore } from 'pinia';
import type { Merchant, AttendanceRecord, RollCallRule, SystemConfig, Announcement } from '@/types';
import { merchants as initialMerchants } from '@/data/mockData';
import * as api from '@/api/client';

// snake_case → camelCase 映射：D1 system_config 表的 key 转为前端字段名
const SYSTEM_CONFIG_KEY_MAP: Record<string, string> = {
  mall_name: 'mallName',
  logo_url: 'logoUrl',
  report_header: 'reportHeader',
  export_watermark: 'exportWatermark',
  theme_color: 'themeColor',
  mall_address: 'mallAddress',
  service_phone: 'servicePhone',
  mall_hours: 'mallHours',
  copyright: 'copyright',
  icp: 'icp',
  checkin_radius: 'checkinRadius',
  location_enabled: 'locationEnabled',
  home_bg_url: 'homeBgUrl',
};

function mapSystemConfig(raw: Record<string, string>): SystemConfig {
  const result: Record<string, string> = {};
  for (const [k, v] of Object.entries(raw)) {
    result[SYSTEM_CONFIG_KEY_MAP[k] || k] = v;
  }
  return result as SystemConfig;
}

// 生成最近 30 天的考勤记录 Mock
function genMockRecords(): AttendanceRecord[] {
  const records: AttendanceRecord[] = [];
  const today = new Date();
  for (let i = 0; i < 30; i++) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    initialMerchants.forEach((m) => {
      let status: AttendanceRecord['status'] = 'unsigned';
      let signedAt: string | undefined;
      const seed = (parseInt(m.id.replace('m', '')) + i * 7) % 10;
      if (i === 0) {
        if (m.signedIn) {
          status = 'signedIn';
          signedAt = m.signedAt;
        } else if (m.absent) {
          status = 'absent';
        } else {
          status = 'unsigned';
        }
      } else if (i < 7) {
        if (seed < 7) {
          status = 'signedIn';
          signedAt = `10:${String(seed * 3).padStart(2, '0')}`;
        } else if (seed < 9) {
          status = 'absent';
        } else {
          status = 'unsigned';
        }
      } else {
        status = 'signedIn';
        signedAt = `10:${String(seed).padStart(2, '0')}`;
      }
      records.push({
        id: `${m.id}-${dateStr}`,
        merchantId: m.id,
        date: dateStr,
        status,
        signedAt,
      });
    });
  }
  return records;
}

interface AdminState {
  merchants: Merchant[];
  records: AttendanceRecord[];
  rule: RollCallRule;
  systemConfig: SystemConfig;
  announcements: Announcement[];
}

export const useAdminStore = defineStore('admin', {
  state: (): AdminState => ({
    merchants: initialMerchants,
    records: genMockRecords(),
    rule: {
      dailyStartTime: '10:00',
      dailyEndTime: '11:00',
      absentThreshold: '11:00',
      remindBefore: 10,
      holidays: ['2026-01-01', '2026-02-10', '2026-05-01', '2026-06-19', '2026-10-01'],
      weeklyOff: [0],
      enableAutoAbsent: true,
    },
    systemConfig: {
      mallName: '名创广场',
      logoUrl: '',
      reportHeader: '商场考勤管理报表',
      exportWatermark: '内部资料 请勿外传',
      themeColor: '#00b578',
      mallAddress: '',
      servicePhone: '',
      mallHours: '',
      copyright: '',
      icp: '',
      checkinRadius: '',
      locationEnabled: '',
      homeBgUrl: '',
    },
    announcements: [],
  }),

  actions: {
    async loadFromApi() {
      try {
        const [merchants, records, rule, rawConfig, announcements] = await Promise.all([
          api.fetchMerchants(),
          api.fetchRecords(),
          api.fetchRules(),
          api.fetchSystemConfig().catch(() => this.systemConfig),
          api.fetchAnnouncements().catch(() => []),
        ]);
        const systemConfig = rawConfig ? mapSystemConfig(rawConfig) : this.systemConfig;
        this.merchants = merchants;
        this.records = records;
        this.rule = rule;
        this.systemConfig = systemConfig;
        this.announcements = announcements;
      } catch {
        console.warn('[store] loadFromApi failed, using local cache');
      }
    },

    async syncFromApi() {
      try {
        const [merchants, records, rule, rawConfig, announcements] = await Promise.all([
          api.fetchMerchants(),
          api.fetchRecords(),
          api.fetchRules(),
          api.fetchSystemConfig().catch(() => this.systemConfig),
          api.fetchAnnouncements().catch(() => []),
        ]);
        const systemConfig = rawConfig ? mapSystemConfig(rawConfig) : this.systemConfig;
        this.merchants = merchants;
        this.records = records;
        this.rule = rule;
        this.systemConfig = systemConfig;
        this.announcements = announcements;
      } catch {
        console.warn('[store] syncFromApi failed, keeping current state');
      }
    },

    addMerchant(m: Omit<Merchant, 'id'>) {
      const id = `m${Date.now()}`;
      this.merchants = [...this.merchants, { ...m, id }];
      api.createMerchant(m).catch((e) => console.warn('[store] createMerchant API failed:', e));
    },

    updateMerchant(id: string, patch: Partial<Merchant>) {
      this.merchants = this.merchants.map((m) => (m.id === id ? { ...m, ...patch } : m));
      api.updateMerchant(id, patch).catch((e) => console.warn('[store] updateMerchant API failed:', e));
    },

    removeMerchant(id: string) {
      this.merchants = this.merchants.filter((m) => m.id !== id);
      api.deleteMerchant(id).catch((e) => console.warn('[store] deleteMerchant API failed:', e));
    },

    setRecordStatus(id: string, status: AttendanceRecord['status'], operator?: string, remark?: string) {
      const signedAt =
        status === 'signedIn'
          ? this.records.find((r) => r.id === id)?.signedAt ?? new Date().toTimeString().slice(0, 5)
          : undefined;
      this.records = this.records.map((r) => (r.id === id ? { ...r, status, signedAt, operator, remark } : r));
      api.updateRecord(id, { status, signedAt, operator, remark }).catch((e) => console.warn('[store] setRecordStatus API failed:', e));
    },

    addRemark(id: string, remark: string) {
      this.records = this.records.map((r) => (r.id === id ? { ...r, remark } : r));
      api.updateRecord(id, { remark }).catch((e) => console.warn('[store] addRemark API failed:', e));
    },

    batchSign(ids: string[], operator: string) {
      const now = new Date().toTimeString().slice(0, 5);
      this.records = this.records.map((r) =>
        ids.includes(r.id) ? { ...r, status: 'signedIn' as const, signedAt: r.signedAt ?? now, operator } : r
      );
      api.batchSignRecords(ids, operator).catch((e) => console.warn('[store] batchSign API failed:', e));
    },

    updateRule(patch: Partial<RollCallRule>) {
      this.rule = { ...this.rule, ...patch };
      api.updateRules(patch).catch((e) => console.warn('[store] updateRule API failed:', e));
    },
  },

  persist: {
    key: 'admin-store-v2',
    storage: localStorage,
    // 不持久化 systemConfig：每次启动从 API 拉取最新值（避免旧 homeBgUrl 等字段缓存导致背景图不更新）
    paths: ['merchants', 'records', 'rule', 'announcements'],
  },
});
