import { createRouter, createWebHistory, type RouteRecordRaw } from 'vue-router';

const routes: RouteRecordRaw[] = [
  { path: '/', name: 'Home', component: () => import('@/pages/RollCallHome.vue') },
  { path: '/merchants', name: 'Merchants', component: () => import('@/pages/MerchantPage.vue') },
  { path: '/records', name: 'Records', component: () => import('@/pages/RecordPage.vue') },
  { path: '/merchant/:id', name: 'MerchantDetail', component: () => import('@/pages/MerchantDetailPage.vue') },
  { path: '/:pathMatch(.*)*', redirect: '/' },
];

const router = createRouter({
  history: createWebHistory('/'),
  routes,
  scrollBehavior: () => ({ top: 0 }),
});

export default router;
